const p = $input.first().json;
const agentId   = $('Webhook').first().json.body.agent_id;
const leadId    = $('Webhook').first().json.body.lead_id;
const companyId = $('Webhook').first().json.body.company_id;
const body = {
  p_agent_id:       agentId,
  p_lead_id:        leadId,
  p_company_id:     companyId,
  p_stage:          p.stage          || null,
  p_interest_level: p.interest_level || null,
  p_notes:          p.notes          || null,
  p_last_action:    p.last_action    || null,
  p_budget:         p.budget != null ? parseFloat(p.budget) : null,
  p_decision_maker: p.decision_maker != null ? Boolean(p.decision_maker) : null,
};
try {
  const data = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://fhkhamwrfwtacwydukvb.supabase.co/rest/v1/rpc/update_memory_from_agent',
    headers: { apikey: "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY", Authorization: "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY", "Content-Type": "application/json" },
    json: true,
    body
  });
  return JSON.stringify({ success: true, data });
} catch(e) {
  return JSON.stringify({ success: false, error: e.message });
}

// Input chega como objeto direto (schemaType manual)
const p = $input.first().json;

const agentId     = $('Webhook').first().json.body.agent_id;
const leadId      = $('Webhook').first().json.body.lead_id;
const companyId   = $('Webhook').first().json.body.company_id;
const contentType = $('Webhook').first().json.body.content_type;

const SUPABASE_URL = 'https://fhkhamwrfwtacwydukvb.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY';

const headers = {
  apikey: SUPABASE_KEY,
  Authorization: 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

// Verificar limite de follow-ups
let currentCount = 0;
try {
  const agentArr = await $helpers.httpRequest({ method: 'GET', headers,
    url: SUPABASE_URL + '/rest/v1/ai_agents?id=eq.' + agentId + '&select=escalate_rules' });
  const agent = Array.isArray(agentArr) ? agentArr[0] : agentArr;
  const maxFollowups = agent?.escalate_rules?.max_followups ?? 5;
  const memArr = await $helpers.httpRequest({ method: 'GET', headers,
    url: SUPABASE_URL + '/rest/v1/agent_lead_memory?agent_id=eq.' + agentId + '&lead_id=eq.' + leadId + '&select=followup_count' });
  const mem = Array.isArray(memArr) ? memArr[0] : memArr;
  currentCount = mem?.followup_count ?? 0;
  if (currentCount >= maxFollowups) {
    return JSON.stringify({ success: false, blocked: true, reason: 'Limite de ' + maxFollowups + ' follow-ups atingido.' });
  }
} catch(e) { /* fail-open */ }

const scheduledFor = p.scheduled_for || new Date(Date.now() + 24*60*60*1000).toISOString();

// Usar RPC upsert_agent_lead_memory para criar ou atualizar o registro
const updates = {
  next_action_at:   scheduledFor,
  next_action_type: 'followup',
  next_action:      p.next_action || 'Retomar contato com o lead'
};
if (p.notes) updates.notes = p.notes;
if (contentType === 'followup') updates.followup_count = currentCount + 1;

try {
  await $helpers.httpRequest({
    method: 'POST', headers: { ...headers, Prefer: 'return=minimal' },
    body: JSON.stringify({
      p_agent_id:   agentId,
      p_lead_id:    leadId,
      p_company_id: companyId,
      p_updates:    updates
    }),
    url: SUPABASE_URL + '/rest/v1/rpc/upsert_agent_lead_memory'
  });
  return JSON.stringify({ success: true, scheduled_for: scheduledFor });
} catch(e) {
  return JSON.stringify({ success: false, error: e.message });
}

const reason = String($input.first().json.motivo || "Escalado pelo agente de IA");
const conversationId = $('Webhook').first().json.body.conversation_id;
const companyId      = $('Webhook').first().json.body.company_id;
try {
  const data = await $helpers.httpRequest({
