  next_action_at:   scheduledFor,
  next_action_type: 'followup',
  next_action:      p.next_action || 'Retomar contato com o lead'
};
if (p.notes) updates.notes = p.notes;
if (contentType === 'followup') updates.followup_count = currentCount + 1;

try {
  await $helpers.httpRequest({
    method: 'POST', headers: { ...headers, Prefer: 'return=minimal' },
    body: JSON.stringify({
      p_agent_id:   agentId,
      p_lead_id:    leadId,
      p_company_id: companyId,
      p_updates:    updates
    }),
    url: SUPABASE_URL + '/rest/v1/rpc/upsert_agent_lead_memory'
  });
  return JSON.stringify({ success: true, scheduled_for: scheduledFor });
} catch(e) {
  return JSON.stringify({ success: false, error: e.message });
}

